#include<bits/stdc++.h>
#define LL long long
using namespace std;
const LL mod = 1e7+7;LL n,dp[60],cnt,ans=1;
LL QP(LL x,LL y){LL as=1;while(y){if(y&1)as=(as*x)%mod;x=(x*x)%mod,y>>=1;}return as;}
int main(){
    cin>>n;
    for(int j=50;j>=0;j--){
        for(int i=50;i>=0;i--)dp[i]+=dp[i-1];
        if((n>>j)&1)dp[cnt++]++;
    }
    dp[cnt]++;
    for(int i=1;i<=50;i++)ans=(ans*QP(i,dp[i]))%mod;
    cout<<ans<<"\n";
    return 0;
}
